from typing import List, Optional
from datetime import datetime
from ..repositories import TicketRepository, UserRepository
from ..factories import TicketFactory
from ..models import Ticket, TicketStatus, TicketPriority


class TicketService:
    """Service for ticket management.

    Follows the Service Layer pattern to orchestrate repository operations.
    """

    def __init__(self, ticket_repo: TicketRepository, user_repo: UserRepository):
        self.ticket_repo = ticket_repo
        self.user_repo = user_repo

    def create_ticket(self, title: str, description: str, reporter_id: str, 
                      priority: TicketPriority = TicketPriority.MEDIUM,
                      assignee_id: Optional[str] = None,
                      tags: List[str] = None) -> Ticket:
        """Create a new ticket."""
        if not self.user_repo.find_by_id(reporter_id):
            raise ValueError("Reporter not found")
        if assignee_id and not self.user_repo.find_by_id(assignee_id):
            raise ValueError("Assignee not found")

        ticket = TicketFactory.create(
            title=title,
            description=description,
            reporter_id=reporter_id,
            priority=priority,
            assignee_id=assignee_id,
            tags=tags or []
        )
        return self.ticket_repo.save(ticket)

    def create_bug(self, title: str, description: str, reporter_id: str, 
                   priority: TicketPriority = TicketPriority.HIGH) -> Ticket:
        """Create a bug ticket."""
        ticket = TicketFactory.create_bug(title, description, reporter_id, priority=priority)
        return self.ticket_repo.save(ticket)

    def create_feature(self, title: str, description: str, reporter_id: str,
                       priority: TicketPriority = TicketPriority.MEDIUM) -> Ticket:
        """Create a feature request ticket."""
        ticket = TicketFactory.create_feature(title, description, reporter_id, priority=priority)
        return self.ticket_repo.save(ticket)

    def get_ticket(self, ticket_id: str) -> Optional[Ticket]:
        """Get a ticket by ID."""
        return self.ticket_repo.find_by_id(ticket_id)

    def get_all_tickets(self) -> List[Ticket]:
        """Get all tickets."""
        return self.ticket_repo.find_all()

    def get_tickets_by_status(self, status: TicketStatus) -> List[Ticket]:
        """Get tickets by status."""
        return self.ticket_repo.find_by_status(status)

    def get_tickets_by_assignee(self, user_id: str) -> List[Ticket]:
        """Get tickets assigned to a user."""
        return self.ticket_repo.find_by_assignee(user_id)

    def get_tickets_by_reporter(self, user_id: str) -> List[Ticket]:
        """Get tickets reported by a user."""
        return self.ticket_repo.find_by_reporter(user_id)

    def get_overdue_tickets(self) -> List[Ticket]:
        """Get all overdue tickets."""
        return self.ticket_repo.find_overdue()

    def update_status(self, ticket_id: str, status: TicketStatus) -> Ticket:
        """Update ticket status."""
        ticket = self.ticket_repo.find_by_id(ticket_id)
        if not ticket:
            raise ValueError("Ticket not found")

        ticket.status = status
        ticket.updated_at = datetime.now()
        return self.ticket_repo.save(ticket)

    def update_priority(self, ticket_id: str, priority: TicketPriority) -> Ticket:
        """Update ticket priority."""
        ticket = self.ticket_repo.find_by_id(ticket_id)
        if not ticket:
            raise ValueError("Ticket not found")

        ticket.priority = priority
        ticket.updated_at = datetime.now()
        return self.ticket_repo.save(ticket)

    def assign_ticket(self, ticket_id: str, assignee_id: str) -> Ticket:
        """Assign ticket to a user."""
        ticket = self.ticket_repo.find_by_id(ticket_id)
        if not ticket:
            raise ValueError("Ticket not found")
        if assignee_id and not self.user_repo.find_by_id(assignee_id):
            raise ValueError("Assignee not found")

        ticket.assignee_id = assignee_id
        ticket.updated_at = datetime.now()
        return self.ticket_repo.save(ticket)

    def add_tag(self, ticket_id: str, tag: str) -> Ticket:
        """Add a tag to a ticket."""
        ticket = self.ticket_repo.find_by_id(ticket_id)
        if not ticket:
            raise ValueError("Ticket not found")

        if tag not in ticket.tags:
            ticket.tags.append(tag)
            ticket.updated_at = datetime.now()
            return self.ticket_repo.save(ticket)
        return ticket

    def delete_ticket(self, ticket_id: str) -> bool:
        """Delete a ticket."""
        return self.ticket_repo.delete(ticket_id)
